input.new_string:
terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.60"
    }
  }
}

data "azurerm_client_config" "current" {}

locals {
  cluster_name = "aks-hypera-${var.environment}-${var.location}"
}

  tags = var.tags

  # Prevent plan drift: AKS auto-upgrades kubernetes_version when
  # automatic_upgrade_channel = "stable". Without this, the next plan
  # would try to downgrade back to var.kubernetes_version.
  lifecycle {
    ignore_changes = [kubernetes_version]
  }
}

input.old_string:
variable "system_node_pool_node_count" {
  description = "Number of nodes in the system node pool (min 2 for HA per NFR11)"
  type        = number
  default     = 2
  validation {
    condition     = var.system_node_pool_node_count >= 2
    error_message = "System node pool must have at least 2 nodes for HA (NFR11)."
  }
}

input.new_string:
variable "system_node_pool_node_count" {
  description = "Number of nodes in the system node pool (min 3 for HA across 3 AZs per NFR11)"
  type        = number
  default     = 3
  validation {
    condition     = var.system_node_pool_node_count >= 3
    error_message = "System node pool must have at least 3 nodes (one per AZ) for HA (NFR11)."
  }
}

