input.new_string:
variable "sap_dns_records" {
  description = "Map of SAP hostname to IP address for DNS A records"
  type        = map(string)
  default     = {}
}

variable "sap_dns_record_ttl" {
  description = "TTL in seconds for SAP DNS A records"
  type        = number
  default     = 300
  validation {
    condition     = var.sap_dns_record_ttl >= 60 && var.sap_dns_record_ttl <= 86400
    error_message = "DNS record TTL must be between 60 and 86400 seconds."
  }
}

input.old_string:
variable "sap_subscription_id" {
  description = "Subscription ID for the SAP VNet (if cross-subscription peering)"
  type        = string
  default     = ""
}

input.new_string:
variable "sap_subscription_id" {
  description = "Subscription ID for the SAP VNet (if cross-subscription peering)"
  type        = string
  default     = ""
  validation {
    condition     = var.sap_subscription_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.sap_subscription_id))
    error_message = "sap_subscription_id must be a valid UUID or empty string."
  }
}

input.old_string:
variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
}

input.new_string:
variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
  validation {
    condition     = contains(["dev", "prd"], var.environment)
    error_message = "Environment must be 'dev' or 'prd'."
  }
}

